/**
 * OpenSSL 3.0 implementation using high-level EVP APIs.
 * Avoids all deprecated RSA_* functions.
 */

void handle_error(void) {
    ERR_print_errors_fp(stderr);
    exit(EXIT_FAILURE);
}

int main() {
    EVP_PKEY *pkey = NULL;
    EVP_PKEY_CTX *ctx = NULL;
    EVP_MD_CTX *md_ctx = NULL;
    unsigned char *sig = NULL;
    size_t sig_len = 0;
    BIGNUM *modulus = NULL;

    const char *message = "High-level EVP message to sign";
    size_t msg_len = strlen(message);

    // 1. Generate a 2048-bit RSA key using EVP_PKEY_CTX
    ctx = EVP_PKEY_CTX_new_id(EVP_PKEY_RSA, NULL);
    if (!ctx) handle_error();

    if (EVP_PKEY_keygen_init(ctx) <= 0) handle_error();

    // Set key length to 2048 bits
    if (EVP_PKEY_CTX_set_rsa_keygen_bits(ctx, 2048) <= 0) handle_error();

    if (EVP_PKEY_keygen(ctx, &pkey) <= 0) handle_error();

    printf("[+] 2048-bit RSA key generated successfully.\n");

    // 2. Sign the SHA-256 digest of the message
    md_ctx = EVP_MD_CTX_new();
    if (!md_ctx) handle_error();

    // EVP_DigestSignInit handles the digest (SHA-256) and the key
    if (EVP_DigestSignInit(md_ctx, NULL, EVP_sha256(), NULL, pkey) <= 0) handle_error();
    if (EVP_DigestSignUpdate(md_ctx, message, msg_len) <= 0) handle_error();

    // Determine signature length
    if (EVP_DigestSignFinal(md_ctx, NULL, &sig_len) <= 0) handle_error();

    sig = malloc(sig_len);
    if (!sig) handle_error();

    // Perform the actual signing
    if (EVP_DigestSignFinal(md_ctx, sig, &sig_len) <= 0) handle_error();

    printf("[+] Message signed. Signature length: %zu bytes\n", sig_len);

    // 3. Extract the modulus 'n' as a BIGNUM using EVP_PKEY_get_bn_param
    // This is the 3.0 way to access internal RSA parameters without casting to RSA*
    if (EVP_PKEY_get_bn_param(pkey, "modulus", &modulus) <= 0) handle_error();

    char *mod_hex = BN_bn2hex(modulus);
    if (mod_hex) {
        printf("[+] Modulus (n) extracted: %s\n", mod_hex);
        OPENSSL_free(mod_hex);
    } else {
        handle_error();
    }

    // Cleanup
    free(sig);
    BN_free(modulus);
    EVP_MD_CTX_free(md_ctx);
    EVP_PKEY_free(pkey);
    EVP_PKEY_CTX_free(ctx);

    return 0;
}
