#include <stdio.h>
#include <string.h>
#include <openssl/evp.h>
#include <openssl/params.h>
#include <openssl/mac.h>

int main(void) {
    const char *key = "secret_key";
    const unsigned char *msg = (unsigned char *)"Hello, OpenSSL 3.0 HMAC!";
    size_t msg_len = strlen((char *)msg);
    unsigned char out[EVP_MAX_MD_SIZE];
    size_t out_len;

    // 1. Fetch the HMAC implementation
    EVP_MAC *mac = EVP_MAC_fetch(NULL, "HMAC", NULL, 0);
    if (mac == NULL) {
        fprintf(stderr, "Failed to fetch HMAC\n");
        return 1;
    }

    // 2. Create a context for the MAC operation
    EVP_MAC_CTX *ctx = EVP_MAC_CTX_new(mac);
    if (ctx == NULL) {
        EVP_MAC_free(mac);
        return 1;
    }

    // 3. Initialize with Key and Digest via OSSL_PARAM
    OSSL_PARAM params[3];
    // Parameter for the secret key
    params[0] = OSSL_PARAM_construct1(OSSL_PKEY_PARAM_KEY, key, strlen(key));
    // Parameter for the digest algorithm name
    params[1] = OSSL_PARAM_construct1(OSSL_PKEY_PARAM_DIGEST, "SHA256", 7); 
    params[2] = NULL;

    if (EVP_MAC_init(ctx, params) <= 0) {
        fprintf(stderr, "EVP_MAC_init failed\n");
        EVP_MAC_CTX_free(ctx);
        EVP_MAC_free(mac);
        return 1;
    }

    // 4. Update (provide the message)
    if (EVP_MAC_update(ctx, msg, msg_len) <= 0) {
        fprintf(stderr, "EVP_MAC_update failed\n");
        EVP_MAC_CTX_free(ctx);
        EVP_MAC_free(mac);
        return 1;
    }

    // 5. Finalize (compute the HMAC)
    if (EVP_MAC_final(ctx, out, &out_len, sizeof(out)) <= 0) {
        fprintf(stderr, "EVP_MAC_final failed\n");
        EVP_MAC_CTX_free(ctx);
        EVP_MAC_free(mac);
        return 1;
    }

    // Output result in hex
    printf("HMAC-SHA256: ");
    for (size_t i = 0; i < out_len; i++) {
        printf("%02x", out[i]);
    }
    printf("\n");

    // Cleanup
    EVP_MAC_CTX_free(ctx);
    EVP_MAC_free(mac);

    return 0;
}
